export function hasRegionList(country: string): boolean {
  return Boolean(country && REGIONS_BY_COUNTRY[country]?.length);
}

export function getRegions(country: string): string[] {
  if (!country) return [];
  return [...(REGIONS_BY_COUNTRY[country] ?? [])];
}

export function getCities(country: string, region: string): string[] {
  if (!country) return [];
  const regionKey = region ? `${country}|${region}` : "";
  if (regionKey && CITIES_BY_REGION[regionKey]?.length) {
    return [...CITIES_BY_REGION[regionKey], CITY_OTHER];
  }
  if (CITIES_BY_COUNTRY[country]?.length) {
    return [...CITIES_BY_COUNTRY[country], CITY_OTHER];
  }
  return [CITY_OTHER];
}

export function resolveCity(city: string, cityCustom: string): string {
  return city === CITY_OTHER ? cityCustom.trim() : city;
}
